import Link from "next/link";
import styles from "./navigation.module.css";
import Navbar from "react-bootstrap/Navbar";
import Nav from "react-bootstrap/Nav";

function Navigation() {
  return (
    <div className={styles.navigation}>
      <Navbar collapseOnSelect expand="lg" className={styles.navigation} variant="neon">
        <Navbar.Brand className={styles.logo} href="#home">Güngör Öztürk</Navbar.Brand>
        <button class="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarNav" aria-controls="responsive-navbar-nav" aria-expanded="false" aria-label="Toggle navigation">
    <span class="navbar-toggler-icon"></span>
  </button>
        <Navbar.Collapse id="responsive-navbar-nav">
          <Nav className="ml-auto">
            <Nav.Link className={styles.links} href="#features">HOME</Nav.Link>
            <Nav.Link className={styles.links} href="#pricing">RESUME</Nav.Link>
          </Nav>
        </Navbar.Collapse>
      </Navbar>
    </div>
  );
}

export default Navigation;
